// Example function to retrieve a problem template from local storage
function getProblemTemplate(problemId: string): string | null {
  if (typeof window !== 'undefined') {
    const templates = localStorage.getItem('problemTemplates');
    if (templates) {
      const parsedTemplates = JSON.parse(templates);
      return parsedTemplates[problemId] || null;
    }
  }
  return null;
}

// Usage:
const template = getProblemTemplate('two-sum');
console.log(template); // Outputs the template if found
